import React from 'react'
import useTreeStore from './useTreeStore'
export const TYPE = {
    FOLDER: 'folder',
    FILE: 'file'
}
function TreeNode({ name, id, type, children, isExpanded }) {
    const showChildren = children && children.length > 0 && isExpanded
    const setIsExpanded = useTreeStore((state) => state.setIsExpanded)

    function renderChildren() {
        return (children.map(({ name, id, type, children }) => {
            return (
                <TreeNode key={id} name={name} type={type} children={children} isExpanded={isExpanded} />
            )
        }))
    }

    function renderer(name, type, isExpanded) {
        if (type === TYPE.FOLDER) {
            return (<div>
                <span>{name}</span>
                {isExpanded ? <span>{'V'}</span> : <span>{'>'}</span>}
            </div>)
        } else {
            return <span>{name}</span>
        }
    }

    function clickHandler(id) {
        setIsExpanded(id)
    }

    return (
        <>
            <li key={id}>
                <button onClick={() => clickHandler(id)}>{renderer(name, type, isExpanded)}</button>
            </li>
            <ul className='folder'>{showChildren && renderChildren()}</ul>
        </>)

}

export default TreeNode
